parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const event = body;
const invoice = event?.data?.object || {};

const customerId = invoice.customer || '';
const subscriptionId = invoice.subscription || '';
const invoiceId = invoice.id || '';
const amountPaid = invoice.amount_paid || 0;
const currency = (invoice.currency || 'usd').toUpperCase();
const amountDisplay = `$${(amountPaid / 100).toFixed(2)} ${currency}`;

return [{ json: {
  customerId,
  subscriptionId,
  invoiceId,
  amountPaid,
  amountDisplay,
  currency,
  updatedAt: new Date().toISOString()
} }];

const users = $input.first().json;
const user = Array.isArray(users) ? users[0] : users;
const parsed = $('Parse Payment Succeeded Payload').first().json;

// Only proceed if user was past_due
const wasPastDue = user?.payment_status === 'past_due';
const planTier = user?.plan_tier || 'starter';

const featureFlags = {
  free: { launchpad_access: true, nova_os_access: false, ai_tools_limit: 3, automation_systems: 0, priority_support: false, white_label: false },
  starter: { launchpad_access: true, nova_os_access: false, ai_tools_limit: 10, automation_systems: 2, priority_support: false, white_label: false },
  pro: { launchpad_access: true, nova_os_access: true, ai_tools_limit: 10, automation_systems: 6, priority_support: true, white_label: false },
  scale: { launchpad_access: true, nova_os_access: true, ai_tools_limit: 10, automation_systems: 6, priority_support: true, white_label: true }
};

const flags = featureFlags[planTier] || featureFlags['starter'];

const planDisplayNames = { free: 'Free', starter: 'Starter ($49/mo)', pro: 'Pro ($149/mo)', scale: 'Scale ($299/mo)' };
const planDisplay = planDisplayNames[planTier] || planTier;

const planFeatureSummary = {
  free: ['3 AI Tools via Launchpad', 'Basic access only'],
  starter: ['All 10 Launchpad AI Tools', '2 Nova OS Automation Systems', 'Standard support'],
  pro: ['All 10 Launchpad AI Tools', 'All 6 Nova OS Automation Systems', 'Priority Support', 'Nova OS Access'],
  scale: ['All 10 Launchpad AI Tools', 'All 6 Nova OS Automation Systems', 'Priority Support', 'White Label', 'Nova OS Access']
};

const featureSummary = planFeatureSummary[planTier] || planFeatureSummary['starter'];

return [{ json: {
  ...parsed,
  email: user?.email || '',
  firstName: user?.first_name || 'there',
  planTier,
  planDisplay,
  flags,
  featureSummary,
  wasPastDue
} }];

